#!/usr/bin/env python3
"""
apply_naked_sweep_flip_guard_v285.py  (SentCom v19.34.285)

Idempotent applier for the CRM overnight-naked-flip fix.

WHAT IT DOES  (patches backend/services/trading_bot_service.py)
  Hunk A: adds module-level _naked_sweep_flip_decision() (direction-aware).
  Hunk B: in _naked_position_sweep, fetches SIGNED live IB positions once.
  Hunk C: before each naked reissue, refuses to reissue the protective EXIT
          bracket when IB is flat/opposite (would flip the position naked) or
          when position data is unverifiable this cycle. Same-side partials
          still proceed (the v235 magnitude clamp shrinks the order).

WHY
  The v235 clamp (live_position_abs) is direction-BLIND, so an overnight desync
  where IB went flat/opposite let the SELL/BUY exit oversell past zero -> naked
  flip. This guard reads the SIGNED position and HALTs that case.

SAFETY
  - Idempotent: no-op once 'v19.34.285' markers exist.
  - Refuses to write unless ALL THREE hunks match exactly once.
  - Timestamped .bak + py_compile validation w/ auto-restore.
  - Hunk text is base64-embedded => byte-exact.

USAGE
  python3 apply_naked_sweep_flip_guard_v285.py
  python3 apply_naked_sweep_flip_guard_v285.py --repo /home/spark-1a60/Trading-and-Analysis-Platform
  python3 apply_naked_sweep_flip_guard_v285.py --dry-run
"""
import argparse
import base64
import os
import py_compile
import shutil
import sys
import time

MARKER = "v19.34.285"

_B64 = {
    "HA_OLD": "bG9nZ2VyID0gbG9nZ2luZy5nZXRMb2dnZXIoX19uYW1lX18pCgoKY2xhc3MgQm90TW9kZShzdHIsIEVudW0pOgo=",
    "HA_NEW": "",
    "HB_OLD": "",
    "HB_NEW": "",
    "HC_OLD": "",
    "HC_NEW": "",
}

def _d(k):
    return base64.b64decode(_B64[k]).decode("utf-8")

HUNKS = [
    ("Hunk A (flip-decision helper)", _d("HA_OLD"), _d("HA_NEW")),
    ("Hunk B (signed IB positions)", _d("HB_OLD"), _d("HB_NEW")),
    ("Hunk C (per-trade flip guard)", _d("HC_OLD"), _d("HC_NEW")),
]


def log(m):
    print(f"[v285-applier] {m}", flush=True)


def find_repo(explicit):
    if explicit:
        return explicit
    here = os.path.abspath(os.path.dirname(__file__))
    for base in (here, os.getcwd(), os.path.expanduser("~/Trading-and-Analysis-Platform")):
        cur = base
        for _ in range(6):
            if os.path.isfile(os.path.join(cur, "backend", "services", "trading_bot_service.py")):
                return cur
            parent = os.path.dirname(cur)
            if parent == cur:
                break
            cur = parent
    return None


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--repo", default=None)
    ap.add_argument("--dry-run", action="store_true")
    args = ap.parse_args()

    repo = find_repo(args.repo)
    if not repo:
        log("ERROR: could not locate backend/services/trading_bot_service.py. Pass --repo.")
        return 2
    path = os.path.join(repo, "backend", "services", "trading_bot_service.py")
    log(f"file: {path}")

    with open(path, "r", encoding="utf-8") as fh:
        content = fh.read()

    if MARKER in content:
        log(f"Already applied ('{MARKER}' present). No changes made.")
        return 0

    for name, old, _new in HUNKS:
        n = content.count(old)
        if n != 1:
            log(f"ERROR: {name} anchor matched {n} times (expected 1). Aborting - nothing written.")
            return 3
    for name, old, new in HUNKS:
        content = content.replace(old, new, 1)
        log(f"staged: {name}")
    if content.count(MARKER) < 1:
        log("ERROR: post-apply marker missing. Aborting.")
        return 4

    if args.dry_run:
        log("DRY-RUN: all three hunks match and would apply cleanly. Nothing written.")
        return 0

    bak = f"{path}.bak.v285.{time.strftime('%Y%m%d-%H%M%S')}"
    shutil.copy2(path, bak)
    log(f"backup: {bak}")
    with open(path, "w", encoding="utf-8") as fh:
        fh.write(content)
    try:
        py_compile.compile(path, doraise=True)
        log("py_compile OK.")
    except py_compile.PyCompileError as e:
        log(f"ERROR: py_compile failed: {e}; restoring backup.")
        shutil.copy2(bak, path)
        return 5

    log("SUCCESS - v19.34.285 naked-sweep flip guard applied.")
    log("Restart the backend service to activate.")
    return 0


if __name__ == "__main__":
    sys.exit(main())
